#include <iostream>
#include <string>
#include <cstdio>

using namespace std;

class Solution {
public:
    string removeConsecutive(string str) {
        string result="";
        for (int i=0;i<str.size()-1;i++)
            if (str[i]!=str[i+1])
                result += str[i];
        return result;
    }
};

